50	    return basePremium * FIRST_INSURANCE_SURCHARGE_MULTIPLIER;
51	  }
52	  if (customer?.yearsAsCustomer !== undefined && customer.yearsAsCustomer >= LOYALTY_DISCOUNT_THRESHOLD) {
53	    return basePremium * LOYALTY_DISCOUNT_MULTIPLIER;
54	  }
55	  return basePremium;
56	};
57	
58	export function calculatePremium(policy: unknown[], customer?: Customer): number {
59	  const items = policy as PolicyItem[];
60	  let basePremium = items.reduce((sum, item) => sum + applyItemSurcharges(item), 0);
61	  basePremium = applyCustomerModifier(basePremium, customer);
62	  return Math.round(basePremium + PROCESSING_FEE);
63	}
