const applyItemSurcharges = (item: PolicyItem): number => {
  const basePremium = ITEM_PREMIUMS[item.type] ?? DEFAULT_PREMIUM;
  const cursedMultiplier = item.cursed ? CURSED_SURCHARGE_MULTIPLIER : 1;
